package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

class SharedFlowToListDestinationTest : TestBase() {

    @Test
    fun testToListUsesDestination() = runTest {
        val sh = MutableSharedFlow<Int>()
        val acc = mutableListOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sh.toList(acc)
        }

        // Ensure collector is subscribed before emitting
        assertEquals(1, sh.subscriptionCount.value)

        sh.emit(1)
        assertEquals(listOf(1), acc)

        sh.emit(2)
        assertEquals(listOf(1, 2), acc)

        job.cancel()
        job.join()
    }
}
"}

